     if (config.queryTimeout) args.push('--query-timeout', config.queryTimeout);
     if (config.bashToolTimeout) args.push('--bash-tool-timeout', config.bashToolTimeout);
     if (config.sessionId) args.push('--session-id', config.sessionId);
     if (config.resume) {
