                 const processId = fs.readFileSync(pidFile, 'utf-8').trim();
                 process.kill(parseInt(processId, 10), 0); // Check if process is running
                 status = '运行中';
              } catch (e: any) {
                  if (e.code === 'ESRCH') {
                      status = '已完成或已中止';
                  } else {
                      status = '无法验证状态';
                  }
              }
         } else {
             status = '已完成或已中止';
         }

         return { id: pid, timestamp, status, logFile, pidFile };
