         return;
     }

     console.log('后台任务状态:\n');
     jobs.forEach(job => {
         const date = new Date(job.timestamp).toLocaleString();
         console.log(`[ID: ${job.id}] (${date}) 状态: ${job.status}`);
     });
 }

 export function result(args: string[]) {
