 export async function getGitDiff(baseBranch: string = 'main'): Promise<string> {
   const safeBase = isSafeGitRef(baseBranch) ? baseBranch : 'main';

   try {
     const { stdout } = await execAsync(`git diff ${safeBase}...HEAD`);
     return stdout;
   } catch (error) {
